pub fn with_memory_type(mut self, memory_type: MemoryType) -> Self {
        self.memory_type = memory_type;
        self
    }
pub fn with_confidence(mut self, value: f32) -> Self {
        if value.is_nan() {
            self.confidence = None;
        } else {
            self.confidence = Some(value.clamp(0.0, 1.0));
        }
        self
    }
